import React, {isValidElement} from 'react';
import {Button} from "../../_compat";
import type {UseFormReturn} from "react-hook-form";
import type {IButtonProps, CustomSubmitButtonProps} from "@lmb-it/kitsconcerto-types";

interface SubmitButtonProps {
    isSubmitting: boolean;
    handleSubmit: () => void;
    submitButtonProps?: CustomSubmitButtonProps;
    formMethods: UseFormReturn<any>;
}

export const SubmitButton = ({isSubmitting, handleSubmit, submitButtonProps, formMethods}: SubmitButtonProps) => {
    // Function → render prop
    if (typeof submitButtonProps === "function") {
        return <>{submitButtonProps(handleSubmit, isSubmitting, formMethods)}</>;
    }

    // ReactElement → render directly
    if (isValidElement(submitButtonProps)) {
        return submitButtonProps;
    }

    // Object or undefined → merge with defaults and render Button
    const props: Omit<IButtonProps<any>, "onClick"> = {
        label: "Submit",
        severity: "secondary",
        isLoadingText: "Please Wait...",
        ...(submitButtonProps && typeof submitButtonProps === "object" ? submitButtonProps : {}),
    };

    return (
        <Button
            {...props}
            onClick={handleSubmit}
            loading={isSubmitting}
            disabled={isSubmitting}
        />
    );
};
